output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?ethnic_group ?ethnic_group_label ?language ?language_label WHERE {
  ?ethnic_group wdt:P31 wd:Q1003578 ; wdt:P17 wd:Q965 .
  OPTIONAL {
    ?ethnic_group rdfs:label ?ethnic_group_label .
    FILTER(LANG(?ethnic_group_label) = 'en')
  }
  OPTIONAL {
    ?ethnic_group wdt:P1178 ?language .
  }
  OPTIONAL {
    ?language rdfs:label ?language_label .
    FILTER(LANG(?language_label) = 'en')
  }
}
